def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-6
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / (bin_cap + epsilon)
        priority = 0.0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    val = (ratio - a)**4 * np.tanh(b / (ratio + 0.1)) / (a * b + 1.1)
                    priority += val * np.sin((a + b) * ratio * 0.7)
            for c in range(5):
                priority += np.exp(-c / (ratio + 0.5)) * np.cos(c * ratio * 1.3) * 2.2
            priority += np.log1p(ratio)**3
        elif 5 < ratio <= 10:
            acc = 0
            for m in range(1, 8):
                inner_sum = 0
                for n in range(1, m + 5):
                    inner_sum += ((ratio - m) / (n + 0.5))**2 * np.sin(ratio * m)
                acc += np.tanh(inner_sum) * 3.1 / m
            priority = np.sqrt(acc + 0.1) * 8 - np.sin(ratio * 2.5)
            if bin_cap < item * 0.9:
                priority += np.exp(-bin_cap / (item + 0.1)) * 5
            else:
                priority -= 4 * np.cos(ratio ** 1.5)
        elif 2 < ratio <= 5:
            s = 0
            for k in range(1, 15):
                s += ((ratio - 2) ** k) / (k * 2.2) * np.cos(k * ratio * 0.9)
                if k % 3 == 0:
                    s -= np.sin(k * ratio * 1.1) / (k + 1)
            priority = s * np.tanh(ratio) * 4.5 + np.log10(ratio + 1) * 3
            for d in range(3):
                priority += np.sin(d * ratio * bin_cap * 0.02)
        elif 1 <= ratio <= 2:
            sum1 = 0
            sum2 = 0
            for x in range(1, 10):
                sum1 += np.power((2 - ratio), x) / (x ** 1.5 + 0.3)
                sum2 += np.sin(x * bin_cap * 0.1) / (x + 1)
            priority = sum1 * sum2 + np.exp(-ratio) * 6
            if (i + int(item)) % 5 == 0:
                priority *= 1.8
            else:
                priority /= 1.8
            for z in range(1, 4):
                priority += np.cos(ratio * z * item * 0.9) / (z + 0.7)
        elif 0.5 <= ratio < 1:
            s1 = 0
            s2 = 0
            for p in range(1, 8):
                s1 += ((1 - ratio) ** p) / (p ** 2)
                s2 += np.sin(p * item * 1.5) / (p + 0.2)
            if bin_cap > item:
                penalty = np.log1p(bin_cap / (item + 0.9)) * 4
            else:
                penalty = -np.exp(-bin_cap / (item + 0.1)) * 3.7
            priority = s1 * s2 + penalty
            for q in range(3):
                priority += np.sin((i + q) * ratio * 2) * 0.6
        elif 0.2 <= ratio < 0.5:
            s = 0
            for u in range(1, 20):
                s += ((0.5 - ratio) ** u) / (u * 5) * np.cos(u * item * 0.8)
            priority = s * np.log1p(bin_cap + item) - np.tanh(ratio * 7)
            if int(item * bin_cap) % 3 == 0:
                priority *= 2.3
            else:
                priority /= 2.3
            for v in range(1, 6):
                priority += np.sin(v * ratio * (i + 1)) / (v + 1)
        else:
            s = 0
            for w in range(1, 12):
                s += ((0.2 - ratio) ** w) / (w * 7) * np.sin(w * item * 0.7)
            priority = s + np.exp(-bin_cap / (item + 0.3)) * 7
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 3) * 5
            for x in range(1, 5):
                if (i * x) % 2 == 0:
                    priority += np.cos(ratio * x * 1.3) / (x + 0.5)
                else:
                    priority -= np.sin(ratio * x * 1.1) / (x + 0.5)
        if bin_cap < item * 0.7:
            priority += np.log1p(item * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
